+          continue;
+        }
+
+        const float min_hot_prob = 0.1f;
+        if (true_prob <= min_hot_prob) {
+          main_proj = if_false_proj;
+        } else if (true_prob >= (1.0f - min_hot_prob)) {
+          main_proj = if_true_proj;
+        } else {
+          continue;
+        }
